public void testRemoveValueAtBeginning() {
    DefaultKeyedValues v = new DefaultKeyedValues();
    v.addValue("K1", 1.0);
    v.addValue("K2", 2.0);
    v.addValue("K3", 3.0);
    v.removeValue("K1");
    assertEquals(-1, v.getIndex("K1"));
    assertEquals(0, v.getIndex("K2"));
    assertEquals(1, v.getIndex("K3"));
    assertEquals(2.0, v.getValue("K2").doubleValue(), EPSILON);
    assertEquals(3.0, v.getValue("K3").doubleValue(), EPSILON);
}

public void testRemoveValueAtEnd() {
    DefaultKeyedValues v = new DefaultKeyedValues();
    v.addValue("K1", 1.0);
    v.addValue("K2", 2.0);
    v.addValue("K3", 3.0);
    v.removeValue("K3");
    assertEquals(-1, v.getIndex("K3"));
    assertEquals(0, v.getIndex("K1"));
    assertEquals(1, v.getIndex("K2"));
    assertEquals(1.0, v.getValue("K1").doubleValue(), EPSILON);
    assertEquals(2.0, v.getValue("K2").doubleValue(), EPSILON);
}

public void testRemoveColumnMultipleRows() {
    DefaultCategoryDataset d = new DefaultCategoryDataset();
    d.addValue(1.0, "R1", "C1");
    d.addValue(2.0, "R1", "C2");
    d.addValue(3.0, "R2", "C1");
    d.addValue(4.0, "R2", "C2");
    d.removeColumn("C1");
    assertEquals(2.0, d.getValue("R1", "C2").doubleValue(), EPSILON);
    assertEquals(4.0, d.getValue("R2", "C2").doubleValue(), EPSILON);
    d.addValue(5.0, "R1", "C1");
    assertEquals(5.0, d.getValue("R1", "C1").doubleValue(), EPSILON);
}
